Bash(cd "D:/claude/25년 주별수량" && node -e "
const XLSX = require\('xlsx'\);
const fs = require\('fs'\);

// 공급수량
const wb1 = XLSX.readFile\('25년도 주차별 생활재 공급수량.xlsx'\);
const ws1 = wb1.Sheets[wb1.SheetNames[0]];
const qty = XLSX.utils.sheet_to_json\(ws1, {header:1}\);

// 매출
const wb2 = XLSX.readFile\('25년도 주차별 생활재 매출.xlsx'\);
const ws2 = wb2.Sheets[wb2.SheetNames[0]];
const sales = XLSX.utils.sheet_to_json\(ws2, {header:1}\);

const items = [];
for\(let i=3; i<qty.length; i++\) {
  const row = qty[i];
  if\(!row || !row[1]\) continue;
  const code = row[0];
  const name = row[1];
  const weeks = [];
  for\(let w=2; w<=53; w++\) {
    weeks.push\(row[w] || 0\);
  }
  const total = row[54] || 0;

  // find matching sales row
  let salesWeeks = new Array\(52\).fill\(0\);
  let salesTotal = 0;
  for\(let j=3; j<sales.length; j++\) {
    if\(sales[j] && sales[j][0] === code && sales[j][1] === name\) {
      for\(let w=2; w<=53; w++\) {
        salesWeeks[w-2] = sales[j][w] || 0;
      }
      salesTotal = sales[j][54] || 0;
      break;
    }
  }

  items.push\({code, name, qty: weeks, qtyTotal: total, sales: salesWeeks, salesTotal}\);
}

fs.writeFileSync\('data.json', JSON.stringify\(items\)\);
console.log\('Items count:', items.length\);
console.log\('Sample:', JSON.stringify\(items[0]\).substring\(0, 200\)\);
")

